(function () {
    // ----------------------------
    // ツールチップ要素
    // ----------------------------
    const tooltip = document.createElement("div");
    Object.assign(tooltip.style, {
        position: "fixed",
        padding: "6px 10px",
        background: "rgba(0,0,0,0.8)",
        color: "#fff",
        borderRadius: "6px",
        fontSize: "13px",
        pointerEvents: "none",
        whiteSpace: "nowrap",
        opacity: "0",
        transition: "opacity 0.15s",
        zIndex: 9999,
    });
    document.body.appendChild(tooltip);

    // ----------------------------
    // ツールチップテキスト（キーは「前方一致部分」）
    // ----------------------------
    const tooltipTexts = {
        r1c17p: "自分が担当している工程のみ表示できます",
        r1c24p: "「マイ工程フィルタ」と「自由フィルタ」によって絞り込まれた時のみこのボタンが有効です",
        r1c30p: "表示する工程を自由に設定する事ができます"
    };

    // ----------------------------
    // イベント付与関数
    // ----------------------------
    function attachEvents(btn, key) {
        if (!btn) return;

        // 既存 handler を削除
        if (btn._mouseenterHandler) {
            btn.removeEventListener("mouseenter", btn._mouseenterHandler);
            btn.removeEventListener("mouseleave", btn._mouseleaveHandler);
        }

        btn._mouseenterHandler = () => {
            tooltip.textContent = tooltipTexts[key];
            tooltip.style.opacity = "1";

            const rect = btn.getBoundingClientRect();
            tooltip.style.left = rect.left + rect.width / 2 + "px";
            tooltip.style.top = rect.top - 30 + "px";
            tooltip.style.transform = "translateX(-50%)";
        };

        btn._mouseleaveHandler = () => {
            tooltip.style.opacity = "0";
        };

        btn.addEventListener("mouseenter", btn._mouseenterHandler);
        btn.addEventListener("mouseleave", btn._mouseleaveHandler);

        console.log("✔ イベント再付与:", btn.id);
    }

    // ----------------------------
    // Forguncy が完全描画した後に呼びたい処理
    // ----------------------------
    let timer = null;
    function delayedCheck() {
        clearTimeout(timer);
        timer = setTimeout(() => {
            Object.keys(tooltipTexts).forEach(key => {
                const selector = `[id^='${key}'][id$='_btn']`;
                const btn = document.querySelector(selector);
                if (btn) attachEvents(btn, key);
            });
        }, 50); // 初期値のまま
    }

    // ----------------------------
    // MutationObserver
    // Forguncy の内部更新すべてを拾う
    // ----------------------------
    const observer = new MutationObserver(delayedCheck);
    observer.observe(document.body, {
        childList: true,
        subtree: true,
        attributes: true,
        characterData: true,
    });

    // ----------------------------
    // Forguncy ページ遷移時にも再チェック
    // ----------------------------
    window.FgcPageLoaded = function () {
        console.log("✔ FgcPageLoaded: Forguncyページロード検出");
        delayedCheck();
    };

})();
